import{_ as l,C as o,o as n,c as s,E as a,w as r,a as i,a0 as d}from"./chunks/framework.CkNTPv-z.js";const y=JSON.parse('{"title":"Malta Healthcare","description":"Healthcare and HRT access for transgender people in Malta","frontmatter":{"layout":"doc","title":"Malta Healthcare","description":"Healthcare and HRT access for transgender people in Malta"},"headers":[],"relativePath":"europe/malta/healthcare.md","filePath":"europe/malta/healthcare.md","lastUpdated":null}'),h={name:"europe/malta/healthcare.md"};function c(p,e,u,g,m,f){const t=o("Badge");return n(),s("div",null,[a(t,{variant:"green"},{default:r(()=>[...e[0]||(e[0]=[i("Informed Consent Model",-1)])]),_:1}),a(t,{variant:"blue"},{default:r(()=>[...e[1]||(e[1]=[i("Public Healthcare System",-1)])]),_:1}),e[2]||(e[2]=d('<h1 id="healthcare-in-malta" tabindex="-1">Healthcare in Malta <a class="header-anchor" href="#healthcare-in-malta" aria-label="Permalink to &quot;Healthcare in Malta&quot;">​</a></h1><h2 id="gender-affirming-healthcare" tabindex="-1">Gender Affirming Healthcare <a class="header-anchor" href="#gender-affirming-healthcare" aria-label="Permalink to &quot;Gender Affirming Healthcare&quot;">​</a></h2><p>Malta provides gender affirming healthcare through its public healthcare system, with the primary clinic at <strong>Mater Dei Hospital</strong> in Msida. The <strong>Gender Wellbeing Clinic</strong> is the national referral centre for transgender healthcare.</p><h2 id="hrt-access" tabindex="-1">HRT Access <a class="header-anchor" href="#hrt-access" aria-label="Permalink to &quot;HRT Access&quot;">​</a></h2><p>Malta follows an informed consent model for hormone therapy:</p><ul><li>No requirement for a formal diagnosis of gender dysphoria</li><li>Self-referral to the Gender Wellbeing Clinic</li><li>Treatment is free through the public healthcare system</li><li>Private endocrinologists also offer informed consent care</li><li>Typical wait times: 1-3 months for initial appointment</li></ul><h3 id="key-clinics" tabindex="-1">Key Clinics <a class="header-anchor" href="#key-clinics" aria-label="Permalink to &quot;Key Clinics&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Clinic</th><th>Location</th><th>Services</th><th>Languages</th><th>Wait Times</th></tr></thead><tbody><tr><td>Gender Wellbeing Clinic - Mater Dei</td><td>Msida</td><td>HRT initiation, monitoring, psychological support</td><td>EN, MT</td><td>1-3 months</td></tr><tr><td>Mater Dei Hospital - Endocrinology</td><td>Msida</td><td>Hormone therapy, monitoring</td><td>EN, MT</td><td>1-2 months</td></tr><tr><td>Private Endocrinologists</td><td>Various</td><td>Informed consent HRT, faster access</td><td>EN</td><td>1-4 weeks</td></tr></tbody></table><h2 id="surgical-options" tabindex="-1">Surgical Options <a class="header-anchor" href="#surgical-options" aria-label="Permalink to &quot;Surgical Options&quot;">​</a></h2><p>Gender affirming surgeries are available through the public system with some procedures covered. Options include:</p><ul><li>Chest/breast surgery (top surgery) — Covered with criteria</li><li>Genital surgery (bottom surgery) — Referral to EU specialists possible</li><li>Facial feminisation surgery — Limited public coverage</li><li>Hysterectomy/oophorectomy — Covered</li></ul><p>For complex surgeries, Malta utilises the <strong>EU Cross-Border Healthcare Directive</strong> to refer patients to specialised centres in other EU countries with costs covered.</p><h2 id="prescription-portability" tabindex="-1">Prescription Portability <a class="header-anchor" href="#prescription-portability" aria-label="Permalink to &quot;Prescription Portability&quot;">​</a></h2><p>As an EU member state, Malta accepts prescriptions from other EU/EEA countries under EU regulations. Key points:</p><ul><li>EU prescriptions valid for up to 30 days</li><li>Recommended to carry a doctor&#39;s letter in English</li><li>Emergency supply without prescription possible in urgent cases</li></ul><table tabindex="0"><thead><tr><th>Medication</th><th>Typical Cost (public)</th><th>Pharmacy Availability</th></tr></thead><tbody><tr><td>Oestradiol (oral/gel)</td><td>Free/€10-15 private</td><td>Widely available</td></tr><tr><td>Testosterone (injectable/gel)</td><td>Free/€15-30 private</td><td>Widely available</td></tr><tr><td>Spironolactone</td><td>Free/€8-12 private</td><td>Available</td></tr><tr><td>GnRH agonists (puberty blockers)</td><td>Free (with approval)</td><td>Specialist order</td></tr></tbody></table><h2 id="mental-health-support" tabindex="-1">Mental Health Support <a class="header-anchor" href="#mental-health-support" aria-label="Permalink to &quot;Mental Health Support&quot;">​</a></h2><ul><li><strong>Gender Wellbeing Clinic</strong> — Integrated psychological support</li><li><strong>MGRM</strong> — Peer support and counselling referrals</li><li><strong>Private psychologists</strong> — Several specialise in gender identity</li></ul><h2 id="resources" tabindex="-1">Resources <a class="header-anchor" href="#resources" aria-label="Permalink to &quot;Resources&quot;">​</a></h2><ul><li><strong>Ministry for Health</strong> — <a href="https://health.gov.mt/" target="_blank" rel="noreferrer">health.gov.mt</a></li><li><strong>Gender Wellbeing Clinic</strong> — Referrals through Mater Dei</li><li><strong>MGRM</strong> — Community support: <a href="https://www.maltagayrights.net/" target="_blank" rel="noreferrer">maltagayrights.net</a></li></ul>',20))])}const v=l(h,[["render",c]]);export{y as __pageData,v as default};
